body.script:
const IS_PC = () => window.innerWidth >= 768;

// 1. 외부 SVG 파일 로드 함수
async function loadMap() {
  try {
    // 캐시 방지를 위해 쿼리스트링 추가
    const response = await fetch('korea_map.svg?v=' + new Date().getTime());
    const svgText = await response.text();
    const mapWrap = document.getElementById('map-zoom-wrap');
    mapWrap.innerHTML = svgText;

    // 로드 후 초기화 실행
    setTimeout(initMapLogic, 100);
  } catch (error) {
    document.getElementById('loading-msg').textContent = '지도를 불러오지 못했습니다.';
  }
}

const regionBg = {
  gangwon: 'linear-gradient(135deg,#eef4ea 0%,#d0e0c8 100%)',
  gyeonggi: 'linear-gradient(135deg,#fdfcf0 0%,#f0e8c0 100%)',
  gyeongnam: 'linear-gradient(135deg,#f0f7fd 0%,#c8e0f0 100%)',
  gyeongbuk: 'linear-gradient(135deg,#fdf2f2 0%,#f0c8c8 100%)',
  jeonnam: 'linear-gradient(135deg,#f2fdf7 0%,#c8f0e0 100%)',
  jeonbuk: 'linear-gradient(135deg,#fcf2fd 0%,#e0c8f0 100%)',
  chungnam: 'linear-gradient(135deg,#fdf8f2 0%,#f0e0c8 100%)',
  chungbuk: 'linear-gradient(135deg,#f2f7fd 0%,#c8d8f0 100%)',
  jeju: 'linear-gradient(135deg,#fff8f0 0%,#ffe0c0 100%)'
};

const pinData = {
  seoul:    { title:'남산타워 나들이', address:'서울특별시 용산구 남산공원길 105', region:'gyeonggi', year:2026, images:['🗼','🌳','🥨'] },
  sokcho:   { title:'속초 바다 여행', address:'강원특별자치도 속초시 해오름로 190', region:'gangwon', year:2026, images:['🌊','🦀','🍦'] },
  busan:    { title:'해운대 산책', address:'부산광역시 해운대구 달맞이길 62번길', region:'gyeongnam', year:2027, images:['🏖️','🏙️','🍲'] },
  yeosu:    { title:'여수 밤바다', address:'전라남도 여수시 돌산읍 돌산로', region:'jeonnam', year:2027, images:['🌊','🦞','🌃'] },
  jeju:     { title:'성산일출봉', address:'제주특별자치도 서귀포시 성산읍 일출로 284-12', region:'jeju', year:2028, images:['🌋','🍊','🌅'] },
};

let currentAddress = '';

function initMapLogic() {
  // 탭 클릭 이벤트
  document.querySelectorAll('.year-tab').forEach(tab => {
    tab.onclick = () => {
      document.querySelectorAll('.year-tab').forEach(t => t.classList.remove('active'));
      tab.classList.add('active');
      const year = tab.dataset.year;
      document.querySelectorAll('.pin-group').forEach(pin => {
        pin.classList.toggle('hidden', year !== 'all' && pin.dataset.year !== year);
      });
      closeCard();
    };
  });

  // 지역 hover 배경
  document.querySelectorAll('.region').forEach(el => {
    el.onmouseenter = () => {
      const r = el.dataset.region; if (!regionBg[r]) return;
      const bg = document.getElementById('bg-layer');
      bg.style.setProperty('--region-gradient', regionBg[r]);
      bg.classList.add('active');
    };
    el.onmouseleave = () => {
      const overlay = document.getElementById('card-overlay');
      const card    = document.getElementById('info-card');
      const cardOpen = overlay.classList.contains('visible') || card.classList.contains('pc-visible');
      if (!cardOpen) document.getElementById('bg-layer').classList.remove('active');
    };
  });

  // 핀 클릭 이벤트
  document.querySelectorAll('.pin-group').forEach(pin => {
    pin.style.cursor = 'pointer';
    pin.onclick = (e) => {
      e.stopPropagation();
      openCard(pin.id);
    };
  });

  initZoomAndDrag();
}

function openCard(pinId) {
  const data = pinData[pinId]; if (!data) return;
  const bg = document.getElementById('bg-layer');
  bg.style.setProperty('--region-gradient', regionBg[data.region] || '');
  bg.classList.add('active');
  document.getElementById('card-title').textContent = data.title;
  document.getElementById('card-address').textContent = data.address;
  document.getElementById('card-year-badge').textContent = data.year + '년';
  currentAddress = data.address;
  const ic = document.getElementById('card-images'); ic.innerHTML = '';
  const empty = document.getElementById('card-empty');
  if (data.images?.length) {
    empty.style.display = 'none';
    data.images.forEach(img => {
      const d = document.createElement('div'); d.className = 'img-placeholder'; d.textContent = img; ic.appendChild(d);
    });
  } else { empty.style.display = 'block'; }
  document.getElementById('copy-btn').textContent = '복사';
  document.getElementById('copy-btn').classList.remove('copied');
  const overlay = document.getElementById('card-overlay');
  const card    = document.getElementById('info-card');
  if (IS_PC()) card.classList.add('pc-visible');
  else overlay.classList.add('visible');
}

function closeCard() {
  document.getElementById('card-overlay').classList.remove('visible');
  document.getElementById('info-card').classList.remove('pc-visible');
  document.getElementById('bg-layer').classList.remove('active');
}

function closeCardOutside(e) {
  if (!IS_PC() && e.target === document.getElementById('card-overlay')) closeCard();
}

function copyAddress() {
  navigator.clipboard.writeText(currentAddress).then(() => {
    const btn = document.getElementById('copy-btn');
    btn.textContent = '복사됨'; btn.classList.add('copied');
    setTimeout(() => { btn.textContent = '복사'; btn.classList.remove('copied'); }, 1500);
  });
}

function initZoomAndDrag() {
  const wrap = document.getElementById('map-zoom-wrap');
  const svg  = document.getElementById('korea-map');
  if (!svg) return;

  let scale = 1, tx = 0, ty = 0;
  const MIN_SCALE = 1, MAX_SCALE = 4;

  function applyTransform() {
    svg.style.transform = `translate(${tx}px, ${ty}px) scale(${scale})`;
    const invScale = 1 / scale;
    document.querySelectorAll('.pin-group').forEach(group => {
      const circle = group.querySelector('.pin-circle');
      const dot    = group.querySelector('.pin-dot');
      const hit    = group.querySelector('circle[fill="transparent"]');
      let s = invScale;
      const isHover = group.matches(':hover') || group.matches(':active');
      if (isHover) s *= 1.4;
      if (circle) circle.style.transform = `scale(${s})`;
      if (dot)    dot.style.transform    = `scale(${s})`;
      if (hit)    hit.style.transform    = `scale(${s})`;
    });
  }

  function zoomTo(newScale, cx, cy) {
    cx = cx ?? wrap.clientWidth  / 2;
    cy = cy ?? wrap.clientHeight / 2;
    const ratio = newScale / scale;
    const newTx = cx - ratio * (cx - tx);
    const newTy = cy - ratio * (cy - ty);
    scale = newScale;
    tx = newTx; ty = newTy;
    applyTransform();
  }

  document.getElementById('btn-zoom-in').onclick = () => zoomTo(Math.min(MAX_SCALE, scale * 1.4));
  document.getElementById('btn-zoom-out').onclick = () => zoomTo(Math.max(MIN_SCALE, scale / 1.4));
  document.getElementById('btn-zoom-reset').onclick = () => { scale = 1; tx = 0; ty = 0; applyTransform(); };

  wrap.onwheel = (e) => {
    e.preventDefault();
    const rect = wrap.getBoundingClientRect();
    const cx = e.clientX - rect.left;
    const cy = e.clientY - rect.top;
    const delta = e.deltaY > 0 ? 0.85 : 1.18;
    zoomTo(Math.max(MIN_SCALE, Math.min(MAX_SCALE, scale * delta)), cx, cy);
  };

  applyTransform();
}

loadMap();
